SELECT * FROM interv_session
WHERE user_id = #{userId}
  AND tenant_id = #{tenantId}
  AND del_flag = '0'
ORDER BY session_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM interv_session
WHERE user_id = #{userId}
  AND tenant_id = #{tenantId}
  AND del_flag = '0'

SELECT * FROM interv_session
WHERE user_id = #{userId}
  AND tenant_id = #{tenantId}
  AND session_date = #{date}
  AND del_flag = '0'
ORDER BY session_time DESC
